  1	import { type FC, type MouseEvent as ReactMouseEvent, type Ref, useState } from 'react';
  2	import { useForkliftTranslation } from 'src/utils/i18n';
  3	
  4	import {
  5	  Button,
  6	  ButtonVariant,
  7	  DataListAction,
  8	  DataListCell,
  9	  DataListItem,
 10	  DataListItemCells,
 11	  DataListItemRow,
 12	  Divider,
 13	  MenuToggle,
 14	  type MenuToggleElement,
 15	  Select,
 16	  SelectGroup,
 17	  SelectList,
 18	  SelectOption,
 19	} from '@patternfly/react-core';
 20	import { MinusCircleIcon } from '@patternfly/react-icons';
 21	
 22	import type { Mapping } from '../utils/types';
 23	
 24	import SelectedOptions from './SelectedOptions';
 25	
 26	type MappingListItemProps = {
 27	  source: string;
 28	  destination: string;
 29	  sources?: string[];
 30	  destinations?: string[];
 31	  additionalDestinations?: string[];
 32	  generalSourcesLabel: string;
 33	  noSourcesLabel: string;
 34	  index: number;
 35	  replaceMapping?: (val: { current: Mapping; next: Mapping }) => void;
 36	  deleteMapping?: (mapping: Mapping) => void;
 37	  isEditable: boolean;
 38	  testId?: string;
 39	};
 40	
 41	export const MappingListItem: FC<MappingListItemProps> = ({
 42	  additionalDestinations,
 43	  deleteMapping,
 44	  destination,
 45	  destinations,
 46	  generalSourcesLabel,
 47	  index,
 48	  isEditable,
 49	  noSourcesLabel,
 50	  replaceMapping,
 51	  source,
 52	  sources,
 53	  testId,
 54	}) => {
 55	  const { t } = useForkliftTranslation();
 56	  const [isSrcOpen, setIsSrcOpen] = useState(false);
 57	  const [isTrgOpen, setIsTrgOpen] = useState(false);
 58	  const [srcSelected, setSrcSelected] = useState<string>(source);
 59	  const [trgSelected, setTrgSelected] = useState<string>(destination);
 60	
 61	  const onSrcToggleClick = () => {
 62	    setIsSrcOpen(!isSrcOpen);
 63	  };
 64	
 65	  const onTrgToggleClick = () => {
 66	    setIsTrgOpen(!isTrgOpen);
 67	  };
 68	
 69	  const toggle =
 70	    (selected: string, isOpen: boolean, onToggleClick: () => void) =>
 71	    (toggleRef: Ref<MenuToggleElement>) => (
 72	      <MenuToggle
 73	        ref={toggleRef}
 74	        onClick={onToggleClick}
 75	        isExpanded={isOpen}
 76	        isDisabled={!isEditable}
 77	        isFullWidth
 78	      >
 79	        {selected}
 80	      </MenuToggle>
 81	    );
 82	
 83	  const onSelectSource = (
 84	    _event: ReactMouseEvent | undefined,
 85	    value: string | number | undefined,
 86	  ) => {
 87	    replaceMapping?.({
 88	      current: { destination, source },
 89	      next: { destination, source: value as string },
 90	    });
 91	
 92	    setSrcSelected(value as string);
 93	    setIsSrcOpen(false);
 94	  };
 95	
 96	  const onSelectDestination = (
 97	    _event: ReactMouseEvent | undefined,
 98	    value: string | number | undefined,
 99	  ) => {
100	    replaceMapping?.({
101	      current: { destination, source },
102	      next: { destination: value as string, source },
103	    });
104	
105	    setTrgSelected(value as string);
106	    setIsTrgOpen(false);
107	  };
108	
109	  // Extract mapping type from testId (e.g., "storage-mappings-list" -> "storage")
110	  const mappingType = testId?.replace('-mappings-list', '') ?? 'mapping';
111	
112	  return (
113	    <DataListItem aria-labelledby="" data-testid={`${mappingType}-mapping-row-${index}`}>
114	      <DataListItemRow>
115	        <DataListItemCells
116	          dataListCells={[
117	            <DataListCell key="source">
118	              {/* Custom select does not support the complex toggle being used here */}
119	              {/* eslint-disable-next-line no-restricted-syntax */}
120	              <Select
121	                isOpen={isSrcOpen}
122	                selected={srcSelected}
123	                onSelect={onSelectSource}
124	                onOpenChange={(nextOpen: boolean) => {
125	                  setIsSrcOpen(nextOpen);
126	                }}
127	                toggle={toggle(srcSelected, isSrcOpen, onSrcToggleClick)}
128	                isScrollable
129	                shouldFocusFirstItemOnOpen={false}
130	                data-testid={`${mappingType}-source-button-${index}`}
131	              >
132	                <SelectList>
133	                  <SelectGroup label={generalSourcesLabel} key="generalSources">
134	                    <SelectedOptions
135	                      isEditable={isEditable}
136	                      noOptionsLabel={noSourcesLabel}
137	                      options={sources}
138	                    />
139	                  </SelectGroup>
140	                </SelectList>
141	              </Select>
142	            </DataListCell>,
143	            <DataListCell key="destination">
144	              {/* Custom select does not support the complex toggle being used here */}
145	              {/* eslint-disable-next-line no-restricted-syntax */}
146	              <Select
147	                isOpen={isTrgOpen}
148	                selected={trgSelected}
149	                onSelect={onSelectDestination}
150	                onOpenChange={(nextOpen: boolean) => {
151	                  setIsTrgOpen(nextOpen);
152	                }}
153	                toggle={toggle(trgSelected, isTrgOpen, onTrgToggleClick)}
154	                shouldFocusFirstItemOnOpen={false}
155	                isScrollable
156	                data-testid={`${mappingType}-target-button-${index}`}
157	              >
158	                <SelectList>
159	                  <SelectedOptions options={destinations} />
160	                  {additionalDestinations && (
161	                    <>
162	                      <Divider />
163	                      {additionalDestinations.map((dest) => (
164	                        <SelectOption key={dest} value={dest}>
165	                          {dest}
166	                        </SelectOption>
167	                      ))}
168	                    </>
169	                  )}
170	                </SelectList>
171	              </Select>
172	            </DataListCell>,
173	          ]}
174	        />
175	        {isEditable && (
176	          <DataListAction
177	            id={`${mappingType}_mapping_list_item_${index}`}
178	            aria-label={t('Actions')}
179	            aria-labelledby=""
180	          >
181	            <Button
182	              onClick={() => {
183	                deleteMapping?.({ destination, source });
184	              }}
185	              variant={ButtonVariant.plain}
186	              aria-label={t('Delete mapping')}
187	              key="delete-action"
188	              icon={<MinusCircleIcon />}
189	              data-testid={`delete-${mappingType}-mapping-button-${index}`}
190	            />
191	          </DataListAction>
192	        )}
193	      </DataListItemRow>
194	    </DataListItem>
195	  );
196	};

